# Programmatic format-rule enforcement with Pydantic
from pydantic import BaseModel, field_validator
from typing import Optional
import json
import anthropic


class AgentResponse(BaseModel):
    """Enforces the FORMAT-1 rule from the system prompt at the code level."""
    summary: str
    actions_taken: list[str]
    confidence: float
    needs_escalation: bool
    draft_action: Optional[dict] = None

    @field_validator("confidence")
    @classmethod
    def confidence_in_range(cls, v: float) -> float:
        if not 0.0 <= v <= 1.0:
            raise ValueError(f"confidence must be 0.0-1.0, got {v}")
        return v


def call_agent_with_format_guard(system_prompt: str, user_message: str) -> AgentResponse:
    client = anthropic.Anthropic()
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=512,
        system=system_prompt,
        messages=[{"role": "user", "content": user_message}],
    )
    raw_text = response.content[0].text
    try:
        data = json.loads(raw_text)
        return AgentResponse(**data)
    except (json.JSONDecodeError, ValueError) as exc:
        # Format rule violated — treat as escalation
        return AgentResponse(
            summary=f"Response parsing failed: {exc}",
            actions_taken=[],
            confidence=0.0,
            needs_escalation=True,
        )
